AND d.deleted = FALSE

    AND d.tags && CAST(#{filter.tags} AS varchar[])


    AND d.data_source = #{filter.source}


    AND d.created_at >= #{filter.dateFrom}


    AND d.created_at <= #{filter.dateTo}



        AND d.metadata ->> '${entry.key}' = #{entry.value}

mapper.select:
SELECT c.id, c.doc_id, c.kb_id, c.content, c.embedding, c.chunk_index, c.is_active, c.created_at, c.updated_at, c.deleted
FROM knowledge_chunk c JOIN knowledge_doc d ON c.doc_id = d.id
FROM knowledge_chunk c
WHERE c.deleted = FALSE AND c.is_active = TRUE AND c.kb_id = #{kbId} AND c.embedding IS NOT NULL AND 1 - (c.embedding <=> CAST(#{queryEmbedding} AS vector)) >= #{threshold}
ORDER BY c.embedding <=> CAST(#{queryEmbedding} AS vector) LIMIT #{topK}
